def process_job(job_data: Any) -> None:
    if isinstance(job_data, dict):
        job_type = job_data.get('type', 'unknown')
        logging.info(f'Processing job type: {job_type}')
        
        if job_type == 'data_processing':
            process_data_job(job_data)
        elif job_type == 'report_generation':
            process_report_job(job_data)
        elif job_type == 'batch_operation':
            process_batch_job(job_data)
        else:
            logging.warning(f'Unknown job type: {job_type}')
            process_generic_job(job_data)
    elif isinstance(job_data, list):
        logging.info(f'Processing list of {len(job_data)} items')
        for item in job_data:
            process_job(item)
    else:
        process_generic_job(job_data)


def process_data_job(job_data: dict) -> None:
    logging.info('Processing data job')
    data = job_data.get('data', [])
    operation = job_data.get('operation', 'transform')
    
    logging.info(f'Data job operation: {operation}, records: {len(data) if isinstance(data, list) else "N/A"}')
    
    if operation == 'transform':
        transformed = [transform_record(record) for record in data]
        logging.info(f'Transformed {len(transformed)} records')
    elif operation == 'aggregate':
        result = aggregate_data(data)
        logging.info(f'Aggregated data result: {result}')
    elif operation == 'filter':
        criteria = job_data.get('criteria', {})
        filtered = [record for record in data if matches_criteria(record, criteria)]
        logging.info(f'Filtered to {len(filtered)} records')


def process_report_job(job_data: dict) -> None:
    logging.info('Processing report generation job')
    report_type = job_data.get('report_type', 'standard')
    parameters = job_data.get('parameters', {})
    
    logging.info(f'Generating {report_type} report with parameters: {parameters}')
    
    report_data = generate_report(report_type, parameters)
    logging.info(f'Report generated with {len(report_data)} entries')


def process_batch_job(job_data: dict) -> None:
    logging.info('Processing batch operation job')
    operations = job_data.get('operations', [])
    
    logging.info(f'Executing {len(operations)} batch operations')
    
    for idx, operation in enumerate(operations):
        logging.info(f'Executing batch operation {idx + 1}/{len(operations)}')
        execute_operation(operation)


def process_generic_job(job_data: Any) -> None:
    logging.info(f'Processing generic job with data type: {type(job_data).__name__}')
    
    if hasattr(job_data, '__dict__'):
        logging.info(f'Object attributes: {list(job_data.__dict__.keys())}')
    
    logging.info('Generic job processing completed')


def transform_record(record: Any) -> Any:
    if isinstance(record, dict):
        return {k: str(v).upper() if isinstance(v, str) else v for k, v in record.items()}
    return record


def aggregate_data(data: list) -> dict:
    result = {
        'count': len(data),
        'types': {}
    }
    
    for item in data:
        item_type = type(item).__name__
        result['types'][item_type] = result['types'].get(item_type, 0) + 1
    
    return result


def matches_criteria(record: Any, criteria: dict) -> bool:
    if not isinstance(record, dict):
        return False
    
    for key, value in criteria.items():
        if record.get(key) != value:
            return False
    
    return True


def generate_report(report_type: str, parameters: dict) -> list:
    report_data = []
    
    if report_type == 'summary':
        report_data = [
            {'metric': 'total', 'value': parameters.get('total', 0)},
            {'metric': 'average', 'value': parameters.get('average', 0)}
        ]
    elif report_type == 'detailed':
        items = parameters.get('items', [])
        report_data = [{'item': item, 'processed': True} for item in items]
    
    return report_data


def execute_operation(operation: dict) -> None:
    op_type = operation.get('type', 'unknown')
    op_data = operation.get('data', {})
    
    logging.info(f'Executing operation: {op_type}')
    
    if op_type == 'update':
        logging.info(f'Update operation on {len(op_data)} items')
    elif op_type == 'delete':
        logging.info(f'Delete operation on {len(op_data)} items')
    elif op_type == 'insert':
        logging.info(f'Insert operation with {len(op_data)} items')


class JobRequest:
    def __init__(self, job_id: str, job_type: str, payload: dict):
        self.job_id = job_id
        self.job_type = job_type
        self.payload = payload
        self.timestamp = None
    
    def __repr__(self):
        return f"JobRequest(job_id={self.job_id}, job_type={self.job_type})"